patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..018788136459 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,6 +8790,69 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  // fcmp (fptrunc X), C -> fcmp X, C' for appropriate predicate and constant
+  // where C' is adjusted for rounding.
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      // Source type (larger) and destination type (smaller)
+      Type *SrcTy = X->getType();
+      const fltSemantics &SrcSem = SrcTy->getScalarType()->getFltSemantics();
+      const fltSemantics &DstSem = Op0->getType()->getScalarType()->getFltSemantics();
+      // Extend constant to source type (exact)
+      APFloat CExt = *C;
+      bool Lossy;
+      CExt.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+      assert(!Lossy && "float to double conversion cannot be lossy");
+      (void)Lossy;
+      // Skip if C is NaN or infinity
+      if (C->isNaN() || C->isInfinity())
+        return nullptr;
+      // Compute half ULP in destination semantics
+      APFloat CPrev = *C;
+      CPrev.next(true);
+      // Convert to source semantics
+      CPrev.convert(SrcSem, APFloat::rmNearestTiesToEven, &Lossy);
+      assert(!Lossy);
+      // halfUlp = (CExt - CPrev) / 2
+      APFloat HalfUlp = CExt;
+      HalfUlp.subtract(CPrev, APFloat::rmNearestTiesToEven);
+      HalfUlp.divide(APFloat(SrcSem, 2), APFloat::rmNearestTiesToEven);
+      // Compute lower and upper bounds
+      APFloat Lower = CExt;
+      Lower.subtract(HalfUlp, APFloat::rmNearestTiesToEven);
+      APFloat Upper = CExt;
+      Upper.add(HalfUlp, APFloat::rmNearestTiesToEven);
+
+      APFloat Bound = Lower;
+      switch (Pred) {
+        case FCmpInst::FCMP_OGE:
+        case FCmpInst::FCMP_UGE:
+        case FCmpInst::FCMP_OGT:
+        case FCmpInst::FCMP_UGT:
+          Bound = Lower;
+          break;
+        case FCmpInst::FCMP_OLE:
+        case FCmpInst::FCMP_ULE:
+        case FCmpInst::FCMP_OLT:
+        case FCmpInst::FCMP_ULT:
+          Bound = Upper;
+          break;
+        default:
+          // Unhandled predicate, bail out.
+          break;
+      }
+      // If predicate is one of the handled ones, return new compare.
+      if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
+          Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT ||
+          Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE ||
+          Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT) {
+        Constant *NewConst = ConstantFP::get(SrcTy, Bound);
+        return new FCmpInst(Pred, X, NewConst, "", &I);
+      }
+    }
+  }
+
   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
   // TODO: Handle non-zero compare constants.

